package com.pos;
import javax.swing.*; import java.awt.*; import java.sql.*;
public class AuthFrame extends JFrame {
 private final JTextField username=new JTextField(18); private final JPasswordField password=new JPasswordField(18);
 public AuthFrame(){ super(AppConstants.APP_NAME); setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE); setSize(500,360); setLocationRelativeTo(null); build(); }
 private void build(){ JPanel all=new JPanel(new BorderLayout(10,10)); all.setBorder(BorderFactory.createEmptyBorder(22,30,22,30)); JPanel top=new JPanel(new GridLayout(3,1)); top.add(UIUtils.title("Point of Sale System")); top.add(new JLabel("Administrator, Cashier and Customer Access")); top.add(new JLabel("Retail Sales, Inventory, Receipts and Loyalty Monitoring")); all.add(top,BorderLayout.NORTH); JPanel form=new JPanel(new GridLayout(4,2,8,8)); form.setBorder(BorderFactory.createTitledBorder("Login")); form.add(new JLabel("Username:")); form.add(username); form.add(new JLabel("Password:")); form.add(password); JButton login=new JButton("Login"),reg=new JButton("Register Customer"),test=new JButton("Test Database"),exit=new JButton("Exit"); form.add(login);form.add(reg);form.add(test);form.add(exit);all.add(form,BorderLayout.CENTER);all.add(new JLabel("Demo: admin / Admin@123     cashier1 / Cashier@123     customer1 / User@123"),BorderLayout.SOUTH);add(all); login.addActionListener(e->login()); password.addActionListener(e->login()); reg.addActionListener(e->new RegisterDialog(this).setVisible(true)); test.addActionListener(e->UIUtils.info(this,DB.test()?"Database connection successful.":"Cannot connect. Import SQL and check config/db.properties.")); exit.addActionListener(e->System.exit(0)); }
 private void login(){ String u=username.getText().trim(), h=PasswordUtil.hash(new String(password.getPassword())); String q="SELECT user_id,username,full_name,role,status FROM users WHERE username=? AND password_hash=?"; try(Connection c=DB.getConnection();PreparedStatement p=c.prepareStatement(q)){p.setString(1,u);p.setString(2,h);ResultSet r=p.executeQuery(); if(!r.next()){UIUtils.info(this,"Invalid username or password.");return;} if(!"ACTIVE".equals(r.getString("status"))){UIUtils.info(this,"Account is inactive.");return;} UserSession s=new UserSession(r.getInt("user_id"),r.getString("username"),r.getString("full_name"),r.getString("role")); Audit.log(s,"LOGIN","Successful login"); dispose(); if("CUSTOMER".equals(s.role)) new UserFrame(s).setVisible(true); else new AdminFrame(s).setVisible(true); }catch(Exception e){UIUtils.error(this,e);} }
}
